const o="https://tubesum.app/api";async function i(r){const e=await fetch(`${o}/transcribe`,{method:"POST",headers:{"Content-Type":"application/json",Accept:"application/json"},body:JSON.stringify({youtube_url:r})});if(!e.ok){const t=await e.json();throw new Error(t.error.message)}return e.json()}async function c(r){const e=await fetch(`${o}/transcribe/${r}`,{headers:{Accept:"application/json"}});if(!e.ok){const t=await e.json();throw new Error(t.error.message)}return e.json()}async function u(r){for(let e=0;e<40;e++){const t=await c(r);if(t.status==="completed"||t.status==="failed")return t;chrome.runtime.sendMessage({type:"SUMMARIZE_PROGRESS",taskId:r,status:t.status}).catch(()=>{}),await new Promise(a=>setTimeout(a,3e3))}throw new Error("Transcription timed out. Please try again.")}chrome.runtime.onMessage.addListener((r,e,t)=>{if(r.type==="SUMMARIZE_REQUEST")return p(r.youtubeUrl).then(t).catch(a=>t({type:"SUMMARIZE_ERROR",error:a.message})),!0;if(r.type==="GET_ACTIVE_TAB_URL")return chrome.tabs.query({active:!0,currentWindow:!0},a=>{var n;const s=((n=a[0])==null?void 0:n.url)??null;t({type:"ACTIVE_TAB_URL",url:s})}),!0});async function p(r){const e=await i(r);if(e.status==="completed")return{type:"SUMMARIZE_SUCCESS",taskId:e.task_id,data:e};const t=await u(e.task_id);return t.status==="failed"?{type:"SUMMARIZE_ERROR",error:t.error_message??"Unknown error"}:{type:"SUMMARIZE_SUCCESS",taskId:t.task_id,data:t}}console.log("[TubeSum] Background service worker started.");
